// src/config.js
// ─────────────────────────────────────────────────────────────────────────────
// Single source of truth for the backend URL.
//
// HOW TO CHANGE FOR CLOUDFLARE TUNNEL:
//   Replace BASE_URL with your backend tunnel URL.
//   e.g. 'https://abc-def-ghi.trycloudflare.com'
//
// Change it here only — all other files import from this one.
// ─────────────────────────────────────────────────────────────────────────────

const BASE_URL = 'https://editors-seller-compounds-qualifying.trycloudflare.com';

// Cloudflare tunnel bypass header.
// Without this, Cloudflare intercepts API calls and returns an HTML warning
// page instead of JSON — causing "Unexpected token '<'" errors.
export const TUNNEL_HEADERS = {
  'ngrok-skip-browser-warning': 'true',
  'CF-Access-Client-Id':        'bypass',
};

// Use this instead of plain fetch() for all API calls.
// Automatically adds the bypass header when going through a tunnel URL.
export function apiFetch(url, options = {}) {
  const isTunnel = !url.startsWith('http://localhost') &&
                   !url.startsWith('http://127.0.0.1');
  return fetch(url, {
    ...options,
    headers: {
      ...(isTunnel ? TUNNEL_HEADERS : {}),
      ...(options.headers || {}),
    },
  });
}

export default BASE_URL;
